namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEnemyNames.DrunkardMonkZombie)]
    public class DrunkardMonkZombie : MonkZombie
    {
        private bool hasDrunk = false;
        private float originalDamage = 0f;

        public DrunkardMonkZombie(string nsp, string name) : base(nsp, name)
        {
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            // ๏ฟฝ๏ฟฝสผ๏ฟฝ๏ฟฝสฑ๏ฟฝ๏ฟฝยผิญสผ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ  
            originalDamage = entity.GetDamage();
            hasDrunk = false;
        }

        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            entity.SetModelDamagePercent();

            // ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝวท๏ฟฝำฆ๏ฟฝรด๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝศพ๏ฟฝะง๏ฟฝ๏ฟฝ  
            CheckAndDrink(entity);
        }

        private void CheckAndDrink(Entity entity)
        {
            // ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝัพ๏ฟฝ๏ฟฝศน๏ฟฝ๏ฟฝฦป๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝัพ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝูผ๏ฟฝ๏ฟฝ  
            if (hasDrunk || entity.IsDead)
                return;

            // ๏ฟฝ๏ฟฝัช๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ50%สฑ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝศพ๏ฟฝ  
            if (entity.Health <= entity.GetMaxHealth() * 0.5f)
            {
                Drink(entity);
            }
        }

        private void Drink(Entity entity)
        {
            // ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝับศพ๏ฟฝ  
            hasDrunk = true;

            // ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ  
            float newDamage = originalDamage * 2f;
            entity.SetDamage(newDamage);

            // ๏ฟฝ๏ฟฝ๏ฟฝลบศพ๏ฟฝ๏ฟฝ๏ฟฝะง๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝัก๏ฟฝ๏ฟฝ  
            entity.PlaySound(VanillaSoundID.anvil);

            // ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝำพ๏ฟฝะง๏ฟฝ๏ฟฝ  
            //var effect = entity.Level.Spawn(VanillaEffectID.levelup, entity.Position + new Vector3(0, 50, 0));
            //if (effect != null)
            //{
            //    effect.SetSize(Vector3.one * 0.5f);
            //}
        }

        // ๏ฟฝ๏ฟฝัก๏ฟฝ๏ฟฝ๏ฟฝแนฉ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝวท๏ฟฝ๏ฟฝับศพ๏ฟฝ  
        public bool HasDrunk()
        {
            return hasDrunk;
        }

        // ๏ฟฝ๏ฟฝัก๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝะด๏ฟฝ๏ฟฝศก๏ฟฝหบ๏ฟฝ๏ฟฝฤท๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝศท๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝศท๏ฟฝ๏ฟฝ๏ฟฝหบ๏ฟฝึต  
        //public override float GetDamage(Entity entity)
        //{
        //    if (hasDrunk)
        //    {
        //        return originalDamage * 2f;
        //    }
        //    return originalDamage;
        //}
    }
}